	@Test
	void replaysEveryTheoremBackedRootRuleAsACompleteTree() {
		TupleExpr leaf = pattern("x");
		assertRewrite(runtime(ObservationMode.BAG), new Join(new SingletonSet(), leaf.clone()),
				RuleId.JOIN_UNIT_IDENTITY, leaf);
		assertRewrite(runtime(ObservationMode.BAG), new Join(leaf.clone(), new SingletonSet()),
				RuleId.JOIN_UNIT_IDENTITY, leaf);
		assertRewrite(runtime(ObservationMode.BAG), new Union(new EmptySet(), leaf.clone()),
				RuleId.UNION_EMPTY_IDENTITY, leaf);
		assertRewrite(runtime(ObservationMode.BAG), new Union(leaf.clone(), new EmptySet()),
				RuleId.UNION_EMPTY_IDENTITY, leaf);
		LocalCertificateReplayer specificationBag = specification(ObservationMode.BAG, ContextMode.ALL_BINDINGS);
		assertRewrite(specificationBag, new LeftJoin(new EmptySet(), leaf.clone()),
				RuleId.LEFT_JOIN_EMPTY_LEFT, new EmptySet());
		assertRewrite(specificationBag, new LeftJoin(leaf.clone(), new EmptySet()),
				RuleId.LEFT_JOIN_EMPTY_RIGHT, leaf);
		assertRewrite(specificationBag, new LeftJoin(leaf.clone(), new SingletonSet()),
				RuleId.LEFT_JOIN_UNIT_RIGHT, leaf);
		assertRewrite(specificationBag, new Difference(new EmptySet(), leaf.clone()),
				RuleId.MINUS_EMPTY_LEFT, new EmptySet());
		assertRewrite(runtime(ObservationMode.BAG), new Difference(leaf.clone(), new EmptySet()),
				RuleId.MINUS_EMPTY_RIGHT, leaf);
		assertRewrite(runtime(ObservationMode.BAG),
				new Filter(leaf.clone(), new ValueConstant(VF.createLiteral(true))),
				RuleId.FILTER_TRUE_IDENTITY, leaf);
		assertRewrite(runtime(ObservationMode.SEQUENCE),
				new Filter(leaf.clone(), new ValueConstant(VF.createLiteral(true))),
				RuleId.FILTER_TRUE_IDENTITY, leaf);
		assertRewrite(runtime(ObservationMode.BAG), new Distinct(new Distinct(leaf.clone())),
				RuleId.DISTINCT_IDEMPOTENT, new Distinct(leaf.clone()));
		assertRewrite(runtime(ObservationMode.SET), new Union(leaf.clone(), leaf.clone()),
				RuleId.UNION_IDEMPOTENT_UNDER_SET_OBSERVATION, leaf);
		assertRewrite(specification(ObservationMode.ASK, ContextMode.ALL_BINDINGS), new Distinct(leaf.clone()),
				RuleId.DISTINCT_OR_SET_OBSERVATION, leaf);
		assertRewrite(specification(ObservationMode.SET, ContextMode.ALL_BINDINGS), new Reduced(leaf.clone()),
				RuleId.REDUCED_HIDDEN_BY_SET_OBSERVATION, leaf);
		assertRewrite(runtime(ObservationMode.BAG), values(List.of()), RuleId.VALUES_EMPTY, new EmptySet());
		assertRewrite(runtime(ObservationMode.BAG), values(List.of(new MapBindingSet())), RuleId.VALUES_UNIT,
				new SingletonSet());
		assertRewrite(specification(ObservationMode.BAG, ContextMode.TOP_LEVEL_EMPTY),
				values(List.of(new MapBindingSet())), RuleId.VALUES_UNIT, new SingletonSet());
		assertRewrite(runtime(ObservationMode.SET), values(List.of(new MapBindingSet(), new MapBindingSet())),
				RuleId.VALUES_UNIT, new SingletonSet());
	}

	/**
	 * RDF4J precompiles a LeftJoin condition before either input is evaluated, so a rule that discards a present
	 * condition can hide a preparation failure. The same applies to an operand that the rewrite drops without
	 * evaluating it.
	 */
	@Test
	void rejectsRuntimeRulesThatElideEagerlyPrecompiledSubtrees() {
		TupleExpr leaf = pattern("x");
		LocalCertificateReplayer runtimeBag = runtime(ObservationMode.BAG);
		ValueConstant condition = new ValueConstant(VF.createLiteral(true));

		assertRejected(runtimeBag, new LeftJoin(leaf.clone(), new EmptySet(), condition.clone()),
				RuleId.LEFT_JOIN_EMPTY_RIGHT);
		assertRejected(runtimeBag, new LeftJoin(leaf.clone(), new SingletonSet(), condition.clone()),
				RuleId.LEFT_JOIN_UNIT_RIGHT);
		assertRejected(runtimeBag, new LeftJoin(new EmptySet(), leaf.clone(), condition.clone()),
				RuleId.LEFT_JOIN_EMPTY_LEFT);
		// The elided operand is an arbitrary subtree, so its evaluation failure survives the rewrite.
		assertRejected(runtimeBag, new LeftJoin(new EmptySet(), leaf.clone()), RuleId.LEFT_JOIN_EMPTY_LEFT);
		assertRejected(runtimeBag, new Difference(new EmptySet(), leaf.clone()), RuleId.MINUS_EMPTY_LEFT);
	}

	/**
	 * Nothing eagerly prepared is discarded here: there is no condition to precompile, and an elided
	 * {@code EmptySet}/{@code SingletonSet} operand cannot fail. These stay available under RDF4J_RUNTIME.
	 */
	@Test
	void keepsRuntimeElisionsThatDiscardNothingFailable() {
		TupleExpr leaf = pattern("x");
		LocalCertificateReplayer runtimeBag = runtime(ObservationMode.BAG);

		assertRewrite(runtimeBag, new LeftJoin(leaf.clone(), new EmptySet()), RuleId.LEFT_JOIN_EMPTY_RIGHT, leaf);
		assertRewrite(runtimeBag, new LeftJoin(leaf.clone(), new SingletonSet()), RuleId.LEFT_JOIN_UNIT_RIGHT, leaf);
		assertRewrite(runtimeBag, new LeftJoin(new EmptySet(), new EmptySet()), RuleId.LEFT_JOIN_EMPTY_LEFT,
				new EmptySet());
		assertRewrite(runtimeBag, new Difference(new EmptySet(), new SingletonSet()), RuleId.MINUS_EMPTY_LEFT,
				new EmptySet());
	}

	@Test
	void appliesComposedRootStepsInSubmittedOrder() {
		TupleExpr leaf = pattern("x");
		TupleExpr expression = new Distinct(new Distinct(new Distinct(leaf.clone())));
		List<CertificateStep> steps = List.of(
				step(RuleId.DISTINCT_IDEMPOTENT),
				step(RuleId.DISTINCT_IDEMPOTENT));

		TupleExpr replayed = runtime(ObservationMode.BAG).replay(expression, ObservationMode.BAG, steps);

		assertTrue(ExactTreeEquality.equal(new Distinct(leaf), replayed));
	}

	@Test
	void rejectsMalformedEnvelopeAndUnsupportedRules() {
		LocalCertificateReplayer bag = runtime(ObservationMode.BAG);
		TupleExpr expression = new Join(new SingletonSet(), pattern("x"));

		assertNull(bag.replay(expression, ObservationMode.SET, List.of(step(RuleId.JOIN_UNIT_IDENTITY))));
		assertNull(bag.replay(expression, ObservationMode.BAG, Collections.singletonList(null)));
		assertNull(bag.replay(expression, ObservationMode.BAG,
				List.of(new CertificateStep(RuleId.JOIN_UNIT_IDENTITY, "$/0", Map.of(), "diagnostic"))));
		assertNull(bag.replay(expression, ObservationMode.BAG,
				List.of(new CertificateStep(
						RuleId.JOIN_UNIT_IDENTITY, "$", Map.of("orientation", "left"), "diagnostic"))));
		assertNull(bag.replay(expression, ObservationMode.BAG,
				List.of(new CertificateStep(RuleId.JOIN_UNIT_IDENTITY, "$", Map.of(), " "))));
		assertNull(bag.replay(expression, ObservationMode.BAG, List.of(step(RuleId.JOIN_COMMUTATIVE))));
	}

	@Test
	void rejectsScopePhysicalPurityAndShapeSideConditionFailures() {
		TupleExpr leaf = pattern("x");
		Join scoped = new Join(new SingletonSet(), leaf.clone());
		scoped.setVariableScopeChange(true);
		Join algorithm = new Join(new SingletonSet(), leaf.clone());
		algorithm.setAlgorithm("HashJoin");
		Join merge = new Join(new SingletonSet(), leaf.clone());
		merge.setMergeJoin(true);
		Join cacheable = new Join(new SingletonSet(), leaf.clone());
		cacheable.setCacheable(true);
		Extension impure = new Extension(new SingletonSet(), new ExtensionElem(new BNodeGenerator(), "generated"));

		for (TupleExpr expression : List.of(scoped, algorithm, merge, cacheable)) {
			assertRejected(runtime(ObservationMode.BAG), expression, RuleId.JOIN_UNIT_IDENTITY);
		}
		assertRejected(runtime(ObservationMode.BAG), new Join(new SingletonSet(), impure.clone()),
				RuleId.JOIN_UNIT_IDENTITY);
		assertRejected(runtime(ObservationMode.BAG), new LeftJoin(new EmptySet(), impure.clone()),
				RuleId.LEFT_JOIN_EMPTY_LEFT);
		assertRejected(runtime(ObservationMode.BAG),
				new LeftJoin(leaf.clone(), new SingletonSet(), new BNodeGenerator()), RuleId.LEFT_JOIN_UNIT_RIGHT);
		assertRejected(runtime(ObservationMode.BAG), new Difference(new EmptySet(), impure.clone()),
				RuleId.MINUS_EMPTY_LEFT);

		for (RuleId rule : List.of(
				RuleId.JOIN_UNIT_IDENTITY,
				RuleId.UNION_EMPTY_IDENTITY,
				RuleId.LEFT_JOIN_EMPTY_LEFT,
				RuleId.LEFT_JOIN_EMPTY_RIGHT,
				RuleId.LEFT_JOIN_UNIT_RIGHT,
				RuleId.MINUS_EMPTY_LEFT,
				RuleId.MINUS_EMPTY_RIGHT,
				RuleId.FILTER_TRUE_IDENTITY,
				RuleId.DISTINCT_IDEMPOTENT,
				RuleId.VALUES_EMPTY,
				RuleId.VALUES_UNIT)) {
			assertRejected(runtime(ObservationMode.BAG), leaf.clone(), rule);
		}
	}

