	private static void assertRewrite(
			LocalCertificateReplayer replayer,
			TupleExpr expression,
			RuleId rule,
			TupleExpr expected) {
		TupleExpr replayed = replayer.replay(expression, observation(replayer), List.of(step(rule)));
		assertTrue(ExactTreeEquality.equal(expected, replayed), () -> rule + " produced " + replayed);
		assertTrue(!ExactTreeEquality.equal(expression, replayed), () -> rule + " did not rewrite the source tree");
	}

	private static void assertRejected(LocalCertificateReplayer replayer, TupleExpr expression, RuleId rule) {
		assertNull(replayer.replay(expression, observation(replayer), List.of(step(rule))), rule.toString());
	}

	private static ObservationMode observation(LocalCertificateReplayer replayer) {
		for (ObservationMode observation : ObservationMode.values()) {
			TupleExpr probe = replayer.replay(new SingletonSet(), observation, List.of());
			if (probe != null) {
				return observation;
			}
		}
		throw new AssertionError("replayer accepted no observation mode");
	}

	private static CertificateStep step(RuleId rule) {
		Map<String, String> parameters = switch (rule) {
		case DISTINCT_IDEMPOTENT, UNION_IDEMPOTENT_UNDER_SET_OBSERVATION -> Map.of(
				"multiplicity", "deduplicate");
		default -> Map.of();
		};
		return new CertificateStep(rule, "$", parameters, "diagnostic");
	}

	private static LocalCertificateReplayer runtime(ObservationMode observation) {
		return new LocalCertificateReplayer(CheckOptions.builder().observationMode(observation).build());
	}

	private static LocalCertificateReplayer specification(
			ObservationMode observation,
			ContextMode contextMode) {
		return new LocalCertificateReplayer(CheckOptions.builder()
				.semanticsTarget(SemanticsTarget.SPARQL_1_1)
				.observationMode(observation)
				.contextMode(contextMode)
				.build());
	}

	private static StatementPattern pattern(String bindingName) {
		return new StatementPattern(
				Var.of("subject"),
				Var.of("predicate", PREDICATE),
				Var.of(bindingName));
	}

	private static BindingSetAssignment values(List<? extends BindingSet> rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingSets(new ArrayList<>(rows));
		return assignment;
	}
